      <div style={{ fontSize: 13, color: "var(--ink-soft)", marginTop: 8 }}>{picked ? (picked === HES_MARK ? "🤔 答案是「" + q.ans.term + "」 " : picked.id === q.ans.id ? "✓ " : "✗ 是「" + q.ans.term + "」 ") + q.ans.reading + " · " + q.ans.meaning : isListen && !heard ? "先听，再选" : "是下面哪个词？"}</div>
