const CSS = "\
@import url('https://fonts.googleapis.com/css2?family=DotGothic16&display=swap');\
:root{\
/* 焦糖木质像素基底（常驻）·默认=白天。深木框 + 奶油卡片 + 绿/红答题反馈保留 */\
--shell-top:#b98a52;--surface:#f4e8ca;--surface-sel:#ecdcb4;--surface2:#e0cda2;--card-edge:#33220e;--knob:#f4e8ca;\
--honey:#d19a3e;--honey-dk:#8f6218;--matcha:#6f9a3c;--matcha-dk:#527a28;--wood:#8a5a2a;\
--blush:#c14a2a;--blush-dk:#8a2e16;--sky:#5a8fb0;--grape:#9b7ab0;--grape-dk:#6f5288;\
--ink:#33220e;--ink-soft:#5e4620;--ink-mid:#4e3212;\
--line:#7a5230;--line-soft:#a67c46;--bevel:#4a3016;--track:#6e4a26;--pill-bg:#e0cda2;\
--danger-bg:#f0d8c0;--danger-fg:#b03a1c;--danger-line:#33220e;--danger-bevel:#4a3016;--ok-bg:#dbe6bc;--warn-bg:#f5e6c0;\
--window:#8a5a2a;--cushion:#8a6038;--ai-off:#c2b088;--switch-off:#a08850;\
--pix-border:#33220e;--pix-shadow:#4a3016;--dot:rgba(51,34,14,.14);\
--cream:#9a6e3e;--room1:#ecdcb2;--room3:#d8c08e;\
}\
/* 夜晚：暗像素（压暗、文字转亮、描边转亮） */\
[data-tod=night]{\
--shell-top:#1e2417;--surface:#2c3322;--surface-sel:#3a4430;--surface2:#262c1c;--card-edge:#6f7d52;--knob:#e8ecd6;\
--honey:#e0b85a;--honey-dk:#b08a3a;--matcha:#9ab86a;--matcha-dk:#6f8a44;--wood:#b0a878;\
--blush:#e07a68;--blush-dk:#b0503e;--sky:#7aa0b8;--grape:#b0a0c8;--grape-dk:#8878a0;\
--ink:#eef0dc;--ink-soft:#b8bca0;--ink-mid:#d0d4b8;\
--line:#6f7d52;--line-soft:#4f5a38;--bevel:rgba(0,0,0,.5);--track:#3a4430;--pill-bg:#2c3a26;\
--danger-bg:#4a2c26;--danger-fg:#f0a090;--danger-line:#6f7d52;--danger-bevel:#000;--ok-bg:#2c3a26;--warn-bg:#3d3a20;\
--cushion:#3a4430;--ai-off:#3a4430;--switch-off:#5a6048;--window:#4a5a38;\
--pix-border:#6f7d52;--pix-shadow:rgba(0,0,0,.6);--dot:rgba(255,255,255,.06);\
}\
/* 季节 × 昼夜：页面底 + 猫屋天空。焦糖皮当前锁 day/summer，此块必须与 :root 焦糖一致(否则覆盖回旧色) */\
[data-tod=day][data-season=spring]{--cream:#9a6e3e;--room1:#ecdcb2;--room3:#d8c08e;}\
[data-tod=day][data-season=summer]{--cream:#9a6e3e;--room1:#ecdcb2;--room3:#d8c08e;}\
[data-tod=day][data-season=autumn]{--cream:#9a6e3e;--room1:#ecdcb2;--room3:#d8c08e;}\
[data-tod=day][data-season=winter]{--cream:#9a6e3e;--room1:#ecdcb2;--room3:#d8c08e;}\
[data-tod=night][data-season=spring]{--cream:#1f2718;--room1:#2a3420;--room3:#1c2416;}\
[data-tod=night][data-season=summer]{--cream:#1a2414;--room1:#22301a;--room3:#142010;}\
[data-tod=night][data-season=autumn]{--cream:#262414;--room1:#34301a;--room3:#221e10;}\
[data-tod=night][data-season=winter]{--cream:#1c2418;--room1:#243020;--room3:#161e14;}\
* { -webkit-tap-highlight-color: transparent; box-sizing: border-box; border-radius:0 !important; font-family:'DotGothic16','PingFang SC','Microsoft YaHei',monospace !important; }\
body { margin: 0; background: var(--cream); transition: background .6s ease; }\
.card { background:var(--surface); border:4px solid var(--pix-border); box-shadow:5px 5px 0 var(--pix-shadow); }\
button{ border:4px solid var(--pix-border) !important; box-shadow:5px 5px 0 var(--pix-shadow) !important; }\
button.no-pix{ border:none !important; box-shadow:none !important; }\
.pressable:active{ transform:translate(2px,2px) !important; box-shadow:2px 2px 0 var(--pix-shadow) !important; }\
.pressable.no-pix:active{ box-shadow:none !important; }\
@keyframes fall{ 0%{transform:translateY(-12px) rotate(0deg);opacity:.9} 100%{transform:translateY(260px) rotate(160deg);opacity:.35} }\
@keyframes petpop{ 0%{transform:translateY(16px) scale(.7);opacity:0} 55%{transform:translateY(-3px) scale(1.06)} 100%{transform:translateY(0) scale(1);opacity:1} }\
.pet-pop{ animation:petpop .28s cubic-bezier(.2,1.35,.5,1) both; }\
@keyframes churuFly{ 0%{transform:translate(0,36vh) scale(.6);opacity:0} 22%{opacity:1} 46%{transform:translate(0,-3vh) scale(1.06);opacity:1} 100%{transform:translate(0,-44vh) scale(.82);opacity:0} }\
.churu-fly{ animation:churuFly .7s cubic-bezier(.3,.8,.5,1) forwards; }\
@keyframes churuSpark{ 0%{transform:scale(0);opacity:0} 40%{transform:scale(1.2);opacity:1} 100%{transform:scale(.6) translateY(-16px);opacity:0} }\
.churu-spark{ animation:churuSpark .5s ease-out .1s both; }\
.cloud { position:absolute; font-size:36px; opacity:.4; animation:floatX 30s linear infinite; }\
.c1 { top:5%; left:-12%; } .c2 { top:15%; left:-32%; animation-delay:-15s; font-size:26px; }\
.pressable { transition:transform .07s; } .pressable:disabled { cursor:not-allowed; opacity:.55; }\
.fade-in { animation:fade .35s ease both; }\
.slide-up { animation:slideUp .3s ease both; } .pop-in { animation:pop .4s cubic-bezier(.2,1.4,.4,1) both; }\
.shake { animation:shake .4s; } .float-soft { animation:floatSoft 3s ease-in-out infinite; }\
.breathe2 { animation:breathe2 1.5s ease-in-out infinite; }\
.pulse-rec { animation:pulseRec 1.1s ease-in-out infinite; }\
@keyframes bob { 0%,100%{transform:translateY(0) scale(1);} 50%{transform:translateY(-3px) scale(1.03);} } \
@keyframes breathe2 { 0%,100%{transform:scale(1) rotate(-2deg);} 50%{transform:scale(1.07) rotate(2deg);} }\
@keyframes fade { from{opacity:0;transform:translateY(7px);} }\
@keyframes slideUp { from{opacity:0;transform:translateY(10px);} }\
@keyframes pop { from{opacity:0;transform:scale(.85);} }\
@keyframes shake { 0%,100%{transform:translateX(0);} 25%{transform:translateX(-6px);} 75%{transform:translateX(6px);} }\
@keyframes floatSoft { 0%,100%{transform:translateY(0);} 50%{transform:translateY(-4px);} }\
@keyframes floatX { from{transform:translateX(0);} to{transform:translateX(150vw);} }\
@keyframes pulseRec { 0%,100%{box-shadow:0 0 0 0 rgba(232,155,134,.5);} 50%{box-shadow:0 0 0 10px rgba(232,155,134,0);} }\
";
